<?php
$pageTitle='Member Messaging';$pageDescription='Stonefellow in-app and email member campaign console.';$pageClass='membership-page admin-catalog-page';
require __DIR__.'/../includes/admin_catalog.php';require_once __DIR__.'/../includes/ops_scheduler_messaging.php';sf_sec_require('admin.members.manage');
if(($_SERVER['REQUEST_METHOD']??'GET')==='POST'){
 $action=(string)($_POST['action']??'');
 if($action==='save_campaign'){$id=sf_msg_save_campaign($_POST,(int)($_POST['campaign_id']??0));sf_admin_flash($id?'success':'error',$id?'Campaign saved.':'Campaign was rejected. Confirm title, subject, body, channel, schedule, URL, and editable status.');sf_admin_redirect($id?sf_url('admin/member-messaging.php?campaign_id='.$id):null);}
 if($action==='seed_recipients'){$id=(int)($_POST['campaign_id']??0);$n=sf_msg_seed_recipients($id);sf_admin_flash($id>0?'success':'error',$id>0?$n.' recipients added to the audience snapshot.':'Campaign not found.');}
 if($action==='send_campaign'){$id=(int)($_POST['campaign_id']??0);$campaign=sf_msg_campaign($id);if(!$campaign)sf_admin_flash('error','Campaign not found.');elseif(in_array((string)$campaign['status'],['sent','archived'],true))sf_admin_flash('error','Sent or archived campaigns cannot be sent again.');else{sf_sched_execute("UPDATE member_message_campaigns SET status='queued',scheduled_at=COALESCE(scheduled_at,NOW()),updated_at=NOW() WHERE id=?",[$id]);$r=sf_msg_send_campaign($id,500);sf_admin_flash((int)$r['failed']>0?'warning':'success','Campaign delivery: '.(int)$r['sent'].' sent, '.(int)$r['failed'].' failed, '.(int)$r['skipped'].' preference-skipped.');}}
 if($action==='send_due'){$r=sf_msg_send_due(20);sf_admin_flash((int)$r['failed']>0?'warning':'success','Due campaigns: '.(int)$r['campaigns'].' campaigns, '.(int)$r['sent'].' sent, '.(int)$r['failed'].' failed, '.(int)$r['skipped'].' skipped.');}
 sf_admin_redirect(sf_url('admin/member-messaging.php'.(!empty($_POST['campaign_id'])?'?campaign_id='.(int)$_POST['campaign_id']:'')));
}
require __DIR__.'/../includes/header.php';$summary=sf_msg_summary();$campaigns=sf_msg_campaigns(120);$selectedId=(int)($_GET['campaign_id']??($campaigns[0]['id']??0));$selected=$selectedId?sf_msg_campaign($selectedId):null;$recipients=$selectedId?sf_sched_fetch_all('SELECT r.*,u.display_name FROM member_message_recipients r LEFT JOIN users u ON u.id=r.user_id WHERE r.campaign_id=? ORDER BY r.id DESC LIMIT 200',[$selectedId]):[];
sf_admin_shell_start('Member Messaging','Campaigns and member notices','Create audience snapshots, honor channel preferences, and deliver duplicate-safe in-app/email messages.','member-messaging');
